  var faturamento = document.querySelector('[name="qual-o-faturamento-mensal-da-sua-empresa"]');
  if (!faturamento) return '';

  var fat = faturamento.value;
  if (fat.indexOf('0 a 10 mil') !== -1) return '0-10k';
  if (fat.indexOf('11 mil a 20 mil') !== -1) return '11k-20k';
  if (fat.indexOf('21 mil a 50 mil') !== -1) return '21k-50k';
  if (fat.indexOf('51 mil a 100 mil') !== -1) return '51k-100k';
  if (fat.indexOf('101 mil a 500 mil') !== -1) return '101k-500k';
  if (fat.indexOf('Acima de 500 mil') !== -1) return '500k+';
  return '';
}

